args.sparql:
SELECT ?player (COUNT(?event) AS ?count) WHERE {
  VALUES ?player { wd:Q2951933 wd:Q1591326 }
  ?player p:P172 ?participation.
  ?participation ps:P172 ?event.
  ?participation pq:P134 wd:Q1595289.
  ?event wdt:P1778 wd:Q1815146.
  ?event wdt:P585 ?eventDate.
  FILTER (YEAR(?eventDate) = 2013)
} GROUP BY ?player ORDER BY DESC(?count)
